1 {if($o-match'học thuyết x'){return 'tên học thuyết giả định con người thiên về thụ động và cần kiểm soát'};if($o-match'học thuyết y'){return 'tên học thuyết nhấn mạnh tự giác và khả năng sáng tạo'};if($o-match'học thuyết z'){return 'tên học thuyết nhấn mạnh gắn bó, an tâm và quan hệ hài hòa'};if($o-match'tổng hợp.*hoạt động|quá trình.*kế hoạch|xây dựng kế hoạch'){return 'cách mô tả một phần của chu trình quản trị, không phải định nghĩa đầy đủ QTNL'};if($o-match'tài năng|tài trí|quan điểm và năng lực'){return 'thuộc năng lực cá nhân của nhà quản trị, không phải nội hàm Thế'};if($o-match'ổn định|tập trung|nhất quán'){return 'thuộc yêu cầu quản trị, không hoàn chỉnh cặp khoa học và nghệ thuật'};if($o-match'tiên quyết|tiên phong|dẫn đầu'){return 'từ chỉ mức độ ưu tiên, không diễn đạt vai trò nền tảng'};if($o-match'khó bắt chước|đa dạng phức tạp'){return 'đặc điểm bản chất của nguồn nhân lực'};if($o-match'lười nhác không|thiếu chí tiến thủ không'){return 'nhận định tích cực của học thuyết Y về bản tính con người'};if($o-match'khuyến khích và yêu thương|cư xử tế nhị|thỏa mãn.*năng suất'){return 'quan điểm coi trọng quan hệ và thỏa mãn của học thuyết Z'};if($o-match'bảo thủ|buông lỏng'){return 'hạn chế gắn với cách quản lý khác, không phải hệ quả trực tiếp của việc quá đề cao quyền lực'};if($o-match'phân chia công việc'){return 'tư tưởng chuyên môn hóa công việc, không phải trọng tâm học thuyết Z'}}
2 {if($o-match'hoạch định nhân lực dài hạn'){return 'cấp hoạch định dài hạn, hướng tới năng lực tương lai'};if($o-match'hoạch định nhân lực trung hạn'){return 'cấp hoạch định trung hạn để cụ thể hóa chính sách'};if($o-match'hoạch định nhân lực ngắn hạn'){return 'cấp hoạch định ngắn hạn gắn kế hoạch tác nghiệp'};if($o-match'dự báo nhu cầu'){return 'nội dung ước lượng số và loại nhân lực doanh nghiệp cần'};if($o-match'dự báo khả năng cung ứng'){return 'nội dung ước lượng nguồn nhân lực có thể huy động'};if($o-match'dự trù ngân sách'){return 'nội dung lượng hóa nguồn lực tài chính cho kế hoạch nhân sự'};if($o-match'tương quan cung cầu'){return 'bước so sánh nhu cầu với khả năng cung ứng'};if($o-match'nhân viên$'){return 'cấp thực thi, không quyết định định hướng chiến lược'};if($o-match'cấp trung'){return 'tầng chuyển chiến lược thành chính sách và chương trình'};if($o-match'cấp cơ sở'){return 'tầng trực tiếp tổ chức công việc hằng ngày'};if($o-match'có lý|có tình|công bằng|công khai'){return 'yêu cầu khi xây dựng và áp dụng chính sách nhân lực'};if($o-match'điều tra xã hội học'){return 'phương pháp thu thập ý kiến, không phải biểu đồ thay thế hay định biên'};if($o-match'dự báo.*dân số'){return 'phương pháp dự báo nguồn cung bên ngoài'};if($o-match'phân quyền rộng'){return 'cách thiết kế quyền hạn, không phải thời hạn hoạch định'};if($o-match'thị trường lao động'){return 'căn cứ bên ngoài về nguồn cung nhân lực'};if($o-match'^[1-6]$|yếu|khá|trung bình|tốt|kém'){return 'mức hoặc giá trị đánh giá, chỉ có ý nghĩa khi dùng đúng thang và ma trận'}}
3 {if($o-match'bản quy trình|quy trình hoạt động'){return 'tài liệu mô tả trình tự vận hành, không phải mô tả hay tiêu chuẩn một công việc'};if($o-match'bản đánh giá|đánh giá thành tích'){return 'tài liệu ghi nhận kết quả thực hiện, không định nghĩa công việc'};if($o-match'nội quy|quy chế'){return 'quy tắc chung của doanh nghiệp, không phải sản phẩm phân tích công việc'};if($o-match'thông báo tuyển dụng'){return 'đầu ra truyền thông tuyển dụng, không phải sản phẩm chính của phân tích công việc'};if($o-match'công việc là cơ sở|đơn vị căn bản|cấu phần'){return 'nhận định đúng về vai trò của công việc trong cơ cấu và QTNL'};if($o-match'kết quả mong muốn|số lượng và chất lượng|tên công việc|nơi làm việc|tình hình thực hiện|máy móc|trang bị'){return 'thông tin mô tả công việc hoặc điều kiện thực hiện'};if($o-match'thu thập|phân tích các thông tin|xử lý các thông tin'){return 'một thao tác hợp lệ trong quá trình phân tích công việc'};if($o-match'lựa chọn$|mô tả$|phân tích$'){return 'tên một hoạt động khác; định nghĩa trong đề nhấn mạnh thiết kế công việc'};if($o-match'nghệ thuật/công việc|kỹ thuật/nghề nghiệp|quá trình/nghề nghiệp'){return 'cặp từ không khớp định nghĩa phân tích là quá trình thu thập thông tin về công việc'};if($o-match'đối tác|nhà cung cấp'){return 'chủ thể bên ngoài không phải nhóm cốt lõi tham gia phân tích công việc'};if($o-match'chức vụ|nghề|nhiệm vụ.*gắn'){return 'khái niệm gần nhưng không phải tên gọi của công việc cụ thể'};if($o-match'^10$'){return 'kết quả đếm thừa một chức danh'};if($o-match'tốc ký'){return 'kỹ thuật ghi chép, không phải phương pháp thu thập chính được lecture nêu'};if($o-match'mức lương'){return 'thông tin đãi ngộ, không phải thành phần cốt lõi của bản mô tả'}}
4 {if($o-match'đúng quy định.*pháp luật|quy định của pháp luật'){return 'yêu cầu tuân thủ pháp lý, không phải đặc trưng cấu trúc hay căn cứ được hỏi'};if($o-match'cấp cơ sở|cấp thấp'){return 'tầng trực tiếp giám sát nhân viên, dưới trưởng phòng có trưởng nhóm'};if($o-match'cấp cao'){return 'tầng lãnh đạo toàn doanh nghiệp, cao hơn trưởng phòng chức năng'};if($o-match'giám đốc công ty'){return 'chủ thể ra quyết định cuối cùng về nhân lực'};if($o-match'trưởng bộ phận'){return 'chủ thể tham mưu chuyên môn, không có quyền quyết định cuối cùng'};if($o-match'trưởng phòng ban'){return 'quản lý chức năng chịu trách nhiệm nhân sự trong đơn vị mình'};if($o-match'ban kiểm soát'){return 'cơ quan giám sát, không điều hành nhân lực hằng ngày'};if($o-match'nền móng|chuyên nghiệp|giảm.*khó khăn'){return 'vai trò hỗ trợ thực hiện chức năng QTNL'};if($o-match'thực thi tất cả|kiểm soát tất cả'){return 'phạm vi quá rộng; bộ phận nhân lực chỉ phụ trách và tham mưu lĩnh vực nhân lực'};if($o-match'lưu giữ hồ sơ|hệ thống thông tin'){return 'nhiệm vụ tác nghiệp hoặc thông tin của bộ phận nhân lực'};if($o-match'hồ sơ khách hàng'){return 'nhiệm vụ CRM hoặc kinh doanh, không thuộc bộ phận nhân lực'};if($o-match'trên 1000|100.*300|300.*1000'){return 'quy mô lớn hoặc trung bình, không phù hợp cấu trúc giản đơn dưới 100 người'};if($o-match'giám sát$|thu hút$|đánh giá$|duy trì nhân lực|đào tạo và phát triển'){return 'một nghiệp vụ nhân lực, không hoàn chỉnh quan hệ bộ máy phục vụ chiến lược'};if($o-match'hài hoà|thống nhất|kế thừa'){return 'nguyên tắc chung khác, không phải tính quyết định của quy mô'};if($o-match'đối thủ cạnh tranh|văn hoá xã hội'){return 'yếu tố môi trường, không phải căn cứ nội bộ trực tiếp trong danh mục lecture'};if($o-match'yêu cầu.*người lao động'){return 'nhu cầu của đối tượng nhân lực, không phải yếu tố quyết định mô hình bộ máy'}}
